/* ---------------------------------------------------------------------- */
/*  HELPERS                                                                */
/* ---------------------------------------------------------------------- */
function useCountUp(target, active, duration = 1400) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!active) return;
    let start = null;
    let raf;
    const step = (ts) => {
      if (!start) start = ts;
      const progress = Math.min((ts - start) / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setVal(target * eased);
      if (progress < 1) raf = requestAnimationFrame(step);
    };
    raf = requestAnimationFrame(step);
    return () => cancelAnimationFrame(raf);
  }, [active, target, duration]);
  return val;
}

function useOnScreen(ref) {
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0.4 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [ref]);
  return visible;
}

function Reveal({ children, delay = 0 }) {
  const ref = useRef(null);
  const visible = useOnScreen(ref);
  return (
    <div
      ref={ref}
      style={{
        transform: visible ? "translateY(0)" : "translateY(28px)",
        opacity: visible ? 1 : 0,
        transition: `opacity 0.7s ease ${delay}ms, transform 0.7s cubic-bezier(.2,.7,.2,1) ${delay}ms`,
      }}
    >
      {children}
    </div>
  );
}

/* ---------------------------------------------------------------------- */
/*  HERO SIGNATURE — converging signal graphic                            */
/* ---------------------------------------------------------------------- */
function SignalGraphic() {
  const lines = [
    { x1: 0, y1: 0, x2: 200, y2: 200, delay: 0 },
    { x1: 400, y1: 0, x2: 200, y2: 200, delay: 0.3 },
    { x1: 0, y1: 400, x2: 200, y2: 200, delay: 0.6 },
    { x1: 400, y1: 400, x2: 200, y2: 200, delay: 0.9 },
    { x1: 200, y1: 0, x2: 200, y2: 200, delay: 0.15 },
    { x1: 200, y1: 400, x2: 200, y2: 200, delay: 0.45 },
  ];
  return (
    <svg viewBox="0 0 400 400" className="w-full h-full" style={{ overflow: "visible" }}>
      <defs>
        <radialGradient id="coreGlow" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="#3454D1" stopOpacity="0.9" />
          <stop offset="100%" stopColor="#3454D1" stopOpacity="0" />
        </radialGradient>
      </defs>
      {[70, 110, 150].map((r, i) => (
        <circle key={r} cx="200" cy="200" r={r} fill="none" stroke="#332B44" strokeWidth="1"
          style={{ animation: `ringPulse 4.5s ease-in-out ${i * 0.5}s infinite` }} />
      ))}
      {lines.map((l, i) => (
        <line key={i} x1={l.x1} y1={l.y1} x2={l.x2} y2={l.y2}
          stroke="#3454D1" strokeWidth="1.5" strokeDasharray="6 10"
          style={{ animation: `flow 3s linear ${l.delay}s infinite`, opacity: 0.55 }} />
      ))}
      <circle cx="200" cy="200" r="90" fill="url(#coreGlow)" />
      <circle cx="200" cy="200" r="10" fill="#F6F7F9" style={{ animation: "corePulse 2.4s ease-in-out infinite" }} />
      <style>{`
        @keyframes flow { from { stroke-dashoffset: 160; } to { stroke-dashoffset: 0; } }
        @keyframes ringPulse { 0%,100% { opacity: 0.35; } 50% { opacity: 0.8; } }
        @keyframes corePulse { 0%,100% { r: 8; opacity: 0.85; } 50% { r: 13; opacity: 1; } }
      `}</style>
    </svg>
  );
}

